mapper.select:
select o.order_id, o.order_no, o.org_id, o.deceased_id, o.customer_name, o.customer_phone, o.package_type, o.amount, o.status, o.pay_time, o.remark, o.create_time, o.update_time, org.org_name, d.name as deceased_name from mem_order o left join mem_organization org on o.org_id = org.org_id left join mem_deceased d on o.deceased_id = d.deceased_id
and o.org_id = #{orgId}
and o.order_no like concat('%', #{orderNo}, '%')
and o.customer_name like concat('%', #{customerName}, '%')
and o.status = #{status}
and o.package_type = #{packageType}
order by o.create_time desc

mapper.update:
update mem_order
order_no = #{orderNo}, org_id = #{orgId}, deceased_id = #{deceasedId}, customer_name = #{customerName}, customer_phone = #{customerPhone}, package_type = #{packageType}, amount = #{amount}, status = #{status}, pay_time = #{payTime}, remark = #{remark}, update_time = #{updateTime},
where order_id = #{orderId}
